type Node<T> = Array<Node<T> | T>;

export class PersistentVector<T> {
  private constructor(
    private readonly root: Node<T>,
    private readonly _size: number,
    private readonly shift: number
  ) {}

  /**
   * Returns an empty persistent vector.
   */
  static empty<T>(): PersistentVector<T> {
    return new PersistentVector([], 0, 0);
  }

  /**
   * The number of elements in the vector.
   */
  get size(): number {
    return this._size;
  }

  /**
   * Returns the element at the specified index.
   * Throws an error if the index is out of range.
   */
  get(i: number): T {
    if (i < 0 || i >= this._size) {
      throw new Error("Index out of range");
    }

    let curr: Node<T> = this.root;
    // Traverse down the trie based on bits of the index
    for (let level = this.shift; level > 0; level -= 5) {
      const idx = (i >> level) & 31;
      curr = curr[idx] as Node<T>;
    }

    return curr[i & 31] as T;
  }

  /**
   * Returns a new PersistentVector with the value appended to the end.
   * The original vector remains unchanged (structural sharing).
   */
  push(value: T): PersistentVector<T> {
    if (this._size === 0) {
      return new PersistentVector([value], 1, 0);
    }

    // If the current root is full (32 elements/children), we increase the tree depth.
    // A root at shift S can hold 32^(S/5 + 1) elements.
    if ((this._size >> this.shift) >= 32) {
      const newRoot: Node<T> = [this.root];
      const newShift = this.shift + 5;
      return new PersistentVector(
        this.pushRecursive(newRoot, newShift, this._size, value),
        this._size + 1,
        newShift
      );
    }

    // Otherwise, push into the existing tree structure.
    return new PersistentVector(
      this.pushRecursive(this.root, this.shift, this._size, value),
      this._size + 1,
      this.shift
    );
  }

  /**
   * Recursively copies the path to the insertion point and adds the value.
   */
  private pushRecursive(node: Node<T>, level: number, i: number, value: T): Node<T> {
    const newNode = [...node];

    if (level === 0) {
      // Leaf node: simply append the value
      newNode.push(value);
    } else {
      const idx = (i >> level) & 31;
      const child = newNode[idx];

      if (child === undefined) {
        // Create a new branch if it doesn't exist
        newNode[idx] = this.createPath(level - 5, value);
      } else {
        // Recurse down and update the path with structural sharing
        newNode[idx] = this.pushRecursive(child as Node<T>, level - 5, i, value);
      }
    }

    return newNode;
  }

  /**
   * Creates a new single-path branch leading to the leaf value.
   */
  private createPath(level: number, value: T): Node<T> {
    if (level === 0) {
      return [value];
    }
    return [this.createPath(level - 5, value)];
  }
}

