export function parse(s: string): Json {
  let pos = 0;

  const skipWhitespace = () => {
    while (pos < s.length && /\s/.test(s[pos])) {
      pos++;
    }
  };

  const peek = () => s[pos];

  const consume = (expected: string) => {
    if (s[pos] !== expected) {
      throw new Error(`Expected ${expected} at position ${pos}`);
    }
    pos++;
  };

  const parseLiteral = (expected: string) => {
    if (s.slice(pos, pos + expected.length) === expected) {
      pos += expected.length;
      return true;
    }
    return false;
  };

  const parseString = (): string => {
    consume('"');
    let result = "";
    while (pos < s.length) {
      const char = s[pos++];
      if (char === '"') return result;
      if (char === '\\') {
        if (pos >= s.length) throw new Error("Unterminated escape sequence");
        const esc = s[pos++];
        switch (esc) {
          case '"': result += '"'; break;
          case '\\': result += '\\'; break;
          case '/': result += '/'; break;
          case 'b': result += '\b'; break;
          case 'f': result += '\f'; break;
          case 'n': result += '\n'; break;
          case 'r': result += '\r'; break;
          case 't': result += '\t'; break;
          case 'u': {
            const hex = s.slice(pos, pos + 4);
            if (hex.length < 4 || !/^[0-9a-fA-F]{4}$/.test(hex)) {
              throw new Error("Invalid unicode escape");
            }
            result += String.fromCharCode(parseInt(hex, 16));
            pos += 4;
            break;
          }
          default: throw new Error(`Invalid escape character: ${esc}`);
        }
      } else {
        result += char;
      }
    }
    throw new Error("Unterminated string");
  };

  const parseNumber = (): number => {
    const match = s.slice(pos).match(/^-?(0|[1-9][0-9]*)(\.[0-9]+)?([eE][+-]?[0-9]+)?/);
    if (!match) throw new Error(`Invalid number at position ${pos}`);
    const numStr = match[0];
    pos += numStr.length;
    return Number(numStr);
  };

  const parseValue = (): Json => {
    skipWhitespace();
    const char = peek();

    if (char === '{') return parseObject();
    if (char === '[') return parseArray();
    if (char === '"') return parseString();
    if (char === '-' || (char >= '0' && char <= '9')) return parseNumber();
    if (parseLiteral("true")) return true;
    if (parseLiteral("false")) return false;
    if (parseLiteral("null")) return null;

    throw new Error(`Unexpected character ${char} at position ${pos}`);
  };

  const parseObject = (): { [key: string]: Json } => {
    consume('{');
    const obj: { [key: string]: Json } = {};
    skipWhitespace();
    if (peek() === '}') {
      pos++;
      return obj;
    }

    while (true) {
      skipWhitespace();
      if (peek() !== '"') throw new Error("Object keys must be double-quoted strings");
      const key = parseString();
      skipWhitespace();
      consume(':');
      obj[key] = parseValue();
      skipWhitespace();

      const next = peek();
      if (next === '}') {
        pos++;
        break;
      } else if (next === ',') {
        pos++;
        skipWhitespace();
        if (peek() === '}') throw new Error("Trailing comma in object");
      } else {
        throw new Error(`Expected , or } in object at position ${pos}`);
      }
    }
    return obj;
  };

