export type ParseQuery<S extends string> = S extends ""
  ? {}
  : S extends `${infer Pair}&${infer Rest}`
  ? ParsePair<Pair> & ParseQuery<Rest>
  : ParsePair<S>;

type ParsePair<P extends string> = P extends `${infer Key}=${infer Value}`
  ? { [K in Key]: Value }
  : {};

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private readonly handlers = new Map<keyof TEvents, unknown[]>();

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const listeners = this.handlers.get(name) ?? [];
    listeners.push(handler);
    this.handlers.set(name, listeners);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const listeners = this.handlers.get(name);
    if (listeners) {
      for (const handler of listeners) {
        (handler as (...args: TEvents[K]) => void)(...args);
      }
    }
  }
}

export class MedianStream {
  private low = new Heap((a, b) => a > b); // Max-heap for the lower half
  private high = new Heap((a, b) => a < b); // Min-heap for the upper half

  add(n: number): void {
    // 1. Add to max-heap (lower half)
    this.low.push(n);

    // 2. Balance: move largest of lower half to upper half
    this.high.push(this.low.pop()!);

    // 3. Maintain size invariant: low can have at most one more element than high
    if (this.high.size() > this.low.size()) {
      this.low.push(this.high.pop()!);
    }
  }

  median(): number {
    const totalSize = this.low.size() + this.high.size();
    if (totalSize === 0) {
      throw new Error("No elements added to stream");
    }

    if (totalSize % 2 !== 0) {
      return this.low.peek()!;
    } else {
      return (this.low.peek()! + this.high.peek()!) / 2;
    }
  }
}

class Heap<T> {
  private data: T[] = [];
  private compare: (a: T, b: T) => boolean;

  constructor(compare: (a: T, b: T) => boolean) {
    this.compare = compare;
  }

  size(): number {
    return this.data.length;
  }

  peek(): T | undefined {
    return this.data[0];
  }

  push(val: T): void {
    this.data.push(val);
    this.bubbleUp(this.data.length - 1);
  }

  pop(): T | undefined {
    if (this.size() === 0) return undefined;
    const root = this.data[0];
    const last = this.data.pop()!;
    if (this.size() > 0) {
      this.data[0] = last;
      this.bubbleDown(0);
    }
    return root;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.compare(this.data[index], this.data[parent])) {
        this.swap(index, parent);
        index = parent;
      } else {
        break;
      }
    }
  }

  private bubbleDown(index: number): void {
    while (true) {
      let target = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < this.data.length && this.compare(this.data[left], this.data[target])) {
        target = left;
      }
      if (right < this.data.length && this.compare(this.data[right], this.data[target])) {
        target = right;
      }

      if (target !== index) {
        this.swap(index, target);
        index = target;
      } else {
        break;
      }
    }
  }

  private swap(i: number, j: number): void {
    const temp = this.data[i];
    this.data[i] = this.data[j];
    this.data[j] = temp;
  }
}
